# ---------------------------------------------------------------------------
# Helper assertions
# ---------------------------------------------------------------------------

def _assert_valid_ndjson(content: str) -> list:
    """Parse every line of an NDJSON payload and return the list of records."""
    assert content.strip(), "NDJSON content must not be empty"
    records = []
    for line_number, line in enumerate(content.strip().splitlines(), start=1):
        line = line.strip()
        if not line:
            continue
        try:
            record = json.loads(line)
        except json.JSONDecodeError as exc:
            pytest.fail(f"Line {line_number} is not valid JSON: {exc}\n  >>> {line!r}")
        records.append(record)
    return records


